Here's an example of a JavaScript object that stores information about an employee and includes methods to calculate their monthly and annual salary:

```javascript
const employee = {
  name: "John Doe",
  hourlyRate: 20,
  hoursWorked: 160,
  bonus: 1000,
  commission: 0.05,
  taxBrackets: [
    { lowerBound: 0, upperBound: 10000, taxRate: 0 },
    { lowerBound: 10001, upperBound: 50000, taxRate: 0.1 },
    { lowerBound: 50001, upperBound: Infinity, taxRate: 0.2 },
  ],
  calculateMonthlySalary: function() {
    return this.hourlyRate * this.hoursWorked;
  },
  calculateAnnualSalary: function() {
    const monthlySalary = this.calculateMonthlySalary();
    const annualSalary = monthlySalary * 12;
    const bonus = this.bonus;
    const commission = monthlySalary * this.commission;
    let totalSalary = annualSalary + bonus + commission;

    for (let i = 0; i < this.taxBrackets.length; i++) {
      const { lowerBound, upperBound, taxRate } = this.taxBrackets[i];
      if (totalSalary > lowerBound && totalSalary <= upperBound) {
        totalSalary -= totalSalary * taxRate;
        break;
      }
    }

    return totalSalary;
  },
};

console.log("Monthly Salary:", employee.calculateMonthlySalary());
console.log("Annual Salary:", employee.calculateAnnualSalary());
```

