function getOddSquaredNumbers(start, end) {
  // Check if the parameters are integers
  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new Error('Both parameters should be integers');
  }

  // Check if the starting number is greater than 0
  if (start <= 0) {
    throw new Error('Starting number should be greater than 0');
  }

  // Check if the ending number is greater than or equal to the starting number
  if (end < start) {
    throw new Error('Ending number should be greater than or equal to the starting number');
  }

  const result = [];

  for (let i = start; i <= end; i++) {
    // Check if the current number is odd
    if (i % 2 !== 0) {
      // Square the odd number and add it to the result array
      result.push(i * i);
    }
  }

  return result;
}
