const char* AutoHideBehaviorToPref(ShelfAutoHideBehavior behavior) {
  switch (behavior) {
    case SHELF_AUTO_HIDE_BEHAVIOR_ALWAYS:
      return kShelfAutoHideBehaviorAlways.c_str();
    case SHELF_AUTO_HIDE_BEHAVIOR_NEVER:
      return "Never";
    default:
      return "Unknown";
  }
}
