Here is the JavaScript code that prints the Fibonacci sequence based on user-provided starting numbers and implements a recursive solution to calculate the nth Fibonacci number with a time complexity of O(log n):

```javascript
function printFibonacci(start1, start2, limit) {
  if (typeof start1 !== 'number' || typeof start2 !== 'number' || typeof limit !== 'number' || start1 < 0 || start2 < 0 || limit < 0) {
    console.log("Invalid input. Please provide positive numeric values.");
    return;
  }

  console.log(start1);
  console.log(start2);

  let fibNum1 = start1;
  let fibNum2 = start2;

  for (let i = 2; i < limit; i++) {
    const nextFibNum = fibNum1 + fibNum2;
    console.log(nextFibNum);

    fibNum1 = fibNum2;
    fibNum2 = nextFibNum;
  }
}

function calculateFibonacci(n) {
  if (typeof n !== 'number' || n < 0) {
    console.log("Invalid input. Please provide a positive numeric value.");
    return;
  }

  if (n <= 1) {
    return n;
  }

  const fibonacci = (matrix) => {
    if (matrix === 1) {
      return [[1, 1], [1, 0]];
    }

    const half = fibonacci(Math.floor(matrix / 2));
    const temp = [[0, 0], [0, 0]];

    temp[0][0] = half[0][0] * half[0][0] + half[0][1] * half[1][0];
    temp[0][1] = half[0][0] * half[0][1] + half[0][1] * half[1][1];
    temp[1][0] = half[1][0] * half[0][0] + half[1][1] * half[1][0];
    temp[1][1] = half[1][0] * half[0][1] + half[1][1] * half[1][1];

    if (matrix % 2 === 0) {
      return temp;
    } else {
      const fibMatrix = [[0, 0], [0, 0]];

      fibMatrix[0][0] = temp[0][0] + temp[0][1];
      fibMatrix[0][1] = temp[0][0];
      fibMatrix[1][0] = temp[1][0] + temp[1][1];
      fibMatrix[1][1] = temp[1][0];

      return fibMatrix;
    }
  }

  const fibMatrix = fibonacci(n);
  return fibMatrix[0][1];
}

// Example usage
printFibonacci(2, 5, 10);
console.log(calculateFibonacci(10));
```

This code first checks if the input values are valid numbers and positive, and if not, it logs an error message. 

The `printFibonacci` function then prints the Fibonacci sequence starting with the given `start1` and `start2` values up to the `limit` specified. It uses a for loop to calculate the next Fibonacci number by adding the previous two numbers in the sequence. 

The `calculateFibonacci` function recursively calculates the nth Fibonacci number using a matrix exponentiation technique, which has a time complexity of O(log n). It checks if the input is valid and returns the nth Fibonacci number if it is less than or equal to 1. 

You can change the values of `start1`, `start2`, `limit`, and `n` as per your requirements.

