```javascript
function generateUniquePrimeNumbers() {
  let primeNumbers = [];
  let sum = 0;

  while (primeNumbers.length < 20) {
    let number = Math.floor(Math.random() * 10000) + 1;

    if (isPrime(number) && !primeNumbers.includes(number)) {
      primeNumbers.push(number);
      sum += number;
    }
  }

  primeNumbers.sort((a, b) => b - a);

  return { primeNumbers, sum };
}

function isPrime(number) {
  if (number <= 1) {
    return false;
  }

  for (let i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) {
      return false;
    }
  }

  return true;
}
```

