from typing import List

def transform_list(input_list: List[int]) -> List[int]:
    if not input_list:
        return []
    elif len(input_list) == 1:
        return [input_list[0] ** 2]
    else:
        output_list = [input_list[i] + input_list[(i + 1) % len(input_list)] for i in range(len(input_list))]
        return output_list
