        raise BasicAuthError("Basic authentication failed for user {}".format(username))
    elif auth_method == "gssapi":
        raise GSSError("GSSAPI authentication failed for user {}".format(username))
    elif auth_method == "token":
        raise TokenAuthError("Token authentication failed for user {}".format(username))

# Handling authentication errors
try:
    authenticate_user("john_doe", "basic")
