Here's an example function in JavaScript that checks if a given positive integer is a prime number using the Miller-Rabin primality test:

```javascript
function isPrime(num) {
  // Check if the input is a positive integer
  if (!Number.isInteger(num) || num <= 1) {
    throw new Error("Input must be a positive integer");
  }

  // Special cases for small prime numbers
  if (num === 2 || num === 3) {
    return true;
  }

  // Check if the number is even
  if (num % 2 === 0) {
    return false;
  }

  // Miller-Rabin primality test
  const iterations = Math.ceil(Math.log2(num));
  for (let i = 0; i < iterations; i++) {
    const a = Math.floor(Math.random() * (num - 3)) + 2; // Random number between 2 and num-2
    if (modularExponentiation(a, num - 1, num) !== 1) {
      return false;
    }
  }

  return true;
}

function modularExponentiation(base, exponent, modulus) {
  if (modulus === 1) {
    return 0;
  }
  let result = 1;
  base = base % modulus;
  while (exponent > 0) {
    if (exponent % 2 === 1) {
      result = (result * base) % modulus;
    }
    exponent = exponent >> 1;
    base = (base * base) % modulus;
  }
  return result;
}
```

To check if the number 7.5 is prime, you can simply call the `isPrime` function with `7.5` as the argument:

```javascript
try {
  console.log(isPrime(7.5));
} catch (error) {
  console.log(error.message); // Output: "Input must be a positive integer"
}
```

This will throw an error since the input is not a positive integer.

